import{_ as e,o as r,c as s,ai as t}from"./chunks/framework.CaiDwmc7.js";const u=JSON.parse('{"title":"Redis 持久化机制（RDB 与 AOF）","description":"","frontmatter":{},"headers":[],"relativePath":"redis/persistence.md","filePath":"redis/persistence.md"}'),n={name:"redis/persistence.md"};function i(d,o,l,a,c,g){return r(),s("div",null,[...o[0]||(o[0]=[t('<h1 id="redis-持久化机制-rdb-与-aof" tabindex="-1">Redis 持久化机制（RDB 与 AOF） <a class="header-anchor" href="#redis-持久化机制-rdb-与-aof" aria-label="Permalink to “Redis 持久化机制（RDB 与 AOF）”">​</a></h1><hr><h3 id="❓-面试官-redis-的数据是存在内存中的-如果服务器宕机或重启-数据会丢失吗-你们生产环境是怎么配置的" tabindex="-1">❓ 面试官：Redis 的数据是存在内存中的，如果服务器宕机或重启，数据会丢失吗？你们生产环境是怎么配置的？ <a class="header-anchor" href="#❓-面试官-redis-的数据是存在内存中的-如果服务器宕机或重启-数据会丢失吗-你们生产环境是怎么配置的" aria-label="Permalink to “❓ 面试官：Redis 的数据是存在内存中的，如果服务器宕机或重启，数据会丢失吗？你们生产环境是怎么配置的？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> Redis 不会丢失数据（或者说最多丢失极少的数据），因为它支持<strong>两种持久化机制</strong>将内存中的数据落盘到硬盘：<strong>RDB（内存快照）</strong> 和 <strong>AOF（追加日志）</strong>。</p><p><strong>📝 详细原理解析：</strong></p><ol><li><p><strong>RDB (Redis Database) - 内存快照</strong>：</p><ul><li>原理：在指定的时间间隔内，把当前内存里的全量数据“拍个照”，生成一个 <code>.rdb</code> 二进制文件覆盖旧文件。</li><li>优点：文件体积小（经过了压缩）；恢复速度极快（直接加载二进制数据到内存），非常适合做全量冷备。</li><li>缺点：会丢失最后一次快照之后的所有修改数据；全量生成快照如果数据量巨大（如几十 GB），会消耗大量 CPU 并在 Fork 子进程瞬间引起主线程阻塞。</li></ul></li><li><p><strong>AOF (Append Only File) - 追加命令日志</strong>：</p><ul><li>原理：Redis 执行的每一次写操作命令（比如 <code>SET</code>、<code>HSET</code>），都会被追加记录到一个 <code>.aof</code> 文本文件中。重启时，只要把这些命令重新执行一遍，就能恢复数据。</li><li>优点：数据安全性极高（可以配置成每秒 fsync 刷盘一次，最多只丢 1 秒数据）。</li><li>缺点：文件体积越来越大；恢复速度慢（需要重放所有的写命令）。</li></ul></li></ol><p><strong>🌟 面试加分项（生产环境实战）：</strong> 面试官常追问：“那你们生产环境到底用哪种？” <strong>答</strong>：生产环境通常采用 <strong>Redis 4.0 引入的混合持久化模式（RDB + AOF）</strong>。</p><ul><li>开启配置 <code>aof-use-rdb-preamble yes</code>。</li><li>在这种模式下，AOF 重写（Rewrite）时，会把当前内存全量数据以 RDB 二进制格式写入新 AOF 文件的开头，然后把后续增量的命令以 AOF 文本格式追加在后面。</li><li>这样既保证了重启时的<strong>极速恢复（读取开头的 RDB）</strong>，又保证了数据的<strong>高安全性（读取后面的 AOF）</strong>。</li></ul><hr><h3 id="❓-面试官-能详细说说-aof-的三种刷盘策略吗-【中级】" tabindex="-1">❓ 面试官：能详细说说 AOF 的三种刷盘策略吗？【中级】 <a class="header-anchor" href="#❓-面试官-能详细说说-aof-的三种刷盘策略吗-【中级】" aria-label="Permalink to “❓ 面试官：能详细说说 AOF 的三种刷盘策略吗？【中级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> AOF 有三种将缓冲区日志刷入硬盘的策略：<code>always</code>（每次写都刷，极慢）、<code>everysec</code>（每秒刷一次，折中方案，生产默认选这个）、<code>no</code>（由操作系统决定什么时候刷，不可控）。</p><p><strong>📝 详细原理解析：</strong> 其实 AOF 写入并不是直接写到硬盘上的 <code>.aof</code> 文件的。由于磁盘 I/O 非常慢，Redis 首先会把命令追加到内存中的 <strong>AOF 缓冲区（aof_buf）</strong>。什么时候把缓冲区的数据真实落盘（系统调用 <code>fsync</code>），就看配置的 <code>appendfsync</code> 参数了：</p><ol><li><strong><code>always</code> (每次写操作都同步)</strong>： <ul><li>原理：只要执行了一个写命令，立刻触发硬盘 <code>fsync</code>。</li><li>评价：数据绝对安全，但性能极差，完全失去了 Redis 高性能的意义。一般不用。</li></ul></li><li><strong><code>everysec</code> (每秒同步一次)</strong>： <ul><li>原理：有一个专门的后台异步线程，每隔 1 秒调用一次 <code>fsync</code> 把缓冲区数据刷盘。</li><li>评价：性能几乎不受影响。即使服务器突然断电，<strong>最多也只会丢失最近 1 秒钟的数据</strong>。<strong>（生产环境默认和推荐的配置）</strong></li></ul></li><li><strong><code>no</code> (操作系统决定)</strong>： <ul><li>原理：Redis 只管把数据写到缓冲，不主动调用 <code>fsync</code>，什么时候真正写入硬盘完全由 Linux 内核说了算（通常是 30 秒左右）。</li><li>评价：性能最好，但极不安全，宕机可能丢失大量数据。</li></ul></li></ol><hr><h3 id="❓-面试官-如果-aof-文件变得超级大-导致磁盘满了或者恢复太慢怎么办-aof-重写机制-【中高级】" tabindex="-1">❓ 面试官：如果 AOF 文件变得超级大，导致磁盘满了或者恢复太慢怎么办？（AOF 重写机制）【中高级】 <a class="header-anchor" href="#❓-面试官-如果-aof-文件变得超级大-导致磁盘满了或者恢复太慢怎么办-aof-重写机制-【中高级】" aria-label="Permalink to “❓ 面试官：如果 AOF 文件变得超级大，导致磁盘满了或者恢复太慢怎么办？（AOF 重写机制）【中高级】”">​</a></h3><p><em>频率：🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 为了防止 AOF 文件无限膨胀，Redis 提供了 <strong>AOF 重写（Rewrite）机制</strong>。它的核心原理不是去读取旧的 AOF 文件进行压缩，而是直接<strong>读取当前内存中的状态数据</strong>，生成一份只包含最新数据的全新 AOF 日志，从而大幅缩减体积。</p><p><strong>📝 详细原理解析：</strong> 假设我连续执行了 100 次 <code>INCR count</code>。</p><ul><li>旧 AOF 文件里：老老实实记录了 100 条 <code>INCR count</code> 命令。</li><li><strong>重写机制</strong>：Redis 发现当前内存里 <code>count</code> 的值是 100，它就不管你过去怎么折腾的了，直接在新 AOF 文件里生成一条终极命令：<code>SET count 100</code>。</li><li>经过重写后，100 条历史日志被压缩成了 1 条，文件体积自然就急剧减小了。</li></ul><p><strong>🌟 面试加分项（底层原理探讨）：</strong> 面试官可能会问：&quot;AOF 重写也是一个耗时操作，它会阻塞主线程处理正常的读写请求吗？&quot; <strong>绝杀回答</strong>： &quot;不会。AOF 重写是由后台子进程 <code>bgrewriteaof</code> 来完成的，不阻塞主线程。 但这里有个坑：子进程重写期间，主线程还在不断接收新的写请求，这些<strong>增量的新数据如何同步给新 AOF 文件？</strong> Redis 为此设计了一个额外的 <strong>AOF 重写缓冲区（aof_rewrite_buf）</strong>。在子进程重写的这段时间里，主线程不仅要把新命令写进旧 AOF 的缓冲，还要同时写进这个重写缓冲区。 当子进程把全量数据重写完后，主线程只需把这个<strong>重写缓冲区</strong>里积压的一点点增量数据追加到新 AOF 文件末尾即可，最后原子地替换掉老文件，整个过程对主线程的阻塞极其短暂。&quot;</p><hr><h3 id="❓-面试官-rdb-做快照的时候-bgsave-能处理客户端正常的写请求吗-如果能-底层是怎么做到不阻塞的-【中高级】" tabindex="-1">❓ 面试官：RDB 做快照的时候（bgsave），能处理客户端正常的写请求吗？如果能，底层是怎么做到不阻塞的？【中高级】 <a class="header-anchor" href="#❓-面试官-rdb-做快照的时候-bgsave-能处理客户端正常的写请求吗-如果能-底层是怎么做到不阻塞的-【中高级】" aria-label="Permalink to “❓ 面试官：RDB 做快照的时候（bgsave），能处理客户端正常的写请求吗？如果能，底层是怎么做到不阻塞的？【中高级】”">​</a></h3><p><em>频率：🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 能处理。底层依靠的是 Linux 操作系统提供的 <strong>COW (Copy-On-Write，写时复制)</strong> 机制。</p><p><strong>📝 详细原理解析：</strong></p><ol><li>Redis 执行 <code>bgsave</code> 命令生成 RDB 快照时，主线程会调用 <code>fork()</code> 系统调用，<strong>生出一个子进程</strong>。</li><li>此时，父子进程<strong>共享同一块物理内存数据</strong>。子进程负责把这块内存的数据默默地写入 <code>.rdb</code> 文件。</li><li><strong>关键点（COW）</strong>：如果在子进程写磁盘期间，有客户端向主线程发来了写请求，要修改某个 Key（比如把 &quot;name&quot; 从 &quot;张三&quot; 改成 &quot;李四&quot;）。Linux 内核并不会让主线程直接修改原物理内存，而是<strong>把这一小块内存页（Page，通常是 4KB）复制一份出来</strong>（这就是写时复制）。</li><li>主线程在<strong>复制出来的新内存页上进行修改</strong>（改成李四），而子进程依然在旧的、未改变的原始内存页上继续生成快照（读到的还是张三）。</li></ol><p><strong>总结：</strong> 借助于 COW 机制，主进程既能不停顿地处理新的写操作，子进程也能获得一个在 fork 瞬间的“静止不变的”完整内存快照。不会发生数据读写冲突。</p>',29)])])}const O=e(n,[["render",i]]);export{u as __pageData,O as default};
